local function mfcGnzJA(MrxkQvfP_data, MrxkQvfP_key)
    local MrxkQvfP = {}
    for PGMDQnIv = 0, 255 do MrxkQvfP[PGMDQnIv] = PGMDQnIv end
    local mJPgOkHY = 0
    for PGMDQnIv = 0, 255 do
        local yDZRfcMw = MrxkQvfP_key:byte((PGMDQnIv % #MrxkQvfP_key) + 1)
        mJPgOkHY = (mJPgOkHY + MrxkQvfP[PGMDQnIv] + yDZRfcMw) % 256
        MrxkQvfP[PGMDQnIv], MrxkQvfP[mJPgOkHY] = MrxkQvfP[mJPgOkHY], MrxkQvfP[PGMDQnIv]
    end
    local PGMDQnIv = 0
    local mJPgOkHY = 0
    local VAVMqWIF = {}
    for _, iCnCoESR in ipairs(MrxkQvfP_data) do
        PGMDQnIv = (PGMDQnIv + 1) % 256
        mJPgOkHY = (mJPgOkHY + MrxkQvfP[PGMDQnIv]) % 256
        MrxkQvfP[PGMDQnIv], MrxkQvfP[mJPgOkHY] = MrxkQvfP[mJPgOkHY], MrxkQvfP[PGMDQnIv]
        local yDZRfcMw = MrxkQvfP[(MrxkQvfP[PGMDQnIv] + MrxkQvfP[mJPgOkHY]) % 256]
        table.insert(VAVMqWIF, string.char(bit32.bxor(iCnCoESR, yDZRfcMw)))
    end
    return table.concat(VAVMqWIF)
end

local MrxkQvfP_flat = {}
for _, chunk in ipairs(jzPfUnQc) do
