return function(gAbEwxQC, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = mfcGnzJA(MrxkQvfP_flat, gAbEwxQC)
    local JNAoTuIy, WouDimmx = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(MrxkQvfP_flat)
    MrxkQvfP_flat = nil
    
    if JNAoTuIy then 
        local result = JNAoTuIy(gAbEwxQC, ...) 
        decrypted = nil
        JNAoTuIy = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "ecco_auto_merge" .. "): " .. tostring(WouDimmx)) 
    end
end
